将u、v数组转置存储，使Column Sweep中按列访问变为按行访问。或者使用数组结构体（AoS）转换为结构体数组（SoA）布局，将p、q数组合并为结构体数组。
// 改为SoA布局
typedef struct { DATA_TYPE p; DATA_TYPE q; } pq_t;
pq_t POLYBENCH_2D(pq, N, N, n, n);

在Column Sweep和Row Sweep的内层循环中，重复计算a*p[i][j-1]+b和d*p[i][j-1]+e，可提取为临时变量。
// 原代码：
// p[i][j] = -c / (a*p[i][j-1]+b);
// 改为：
DATA_TYPE denom = a*p[i][j-1] + b;
p[i][j] = -c / denom;
q[i][j] = (-d*u[j][i-1]+(1.0+2.0*d)*u[j][i] - f*u[j][i+1]-a*q[i][j-1]) / denom;

在Row Sweep的内层循环中，对j循环进行展开，并使用编译器指令提示向量化。
#pragma omp simd
for (j=1; j<_PB_N-1; j+=4) {
  // 手动展开4次迭代
  p[i][j] = -f / (d*p[i][j-1]+e);
  p[i][j+1] = -f / (d*p[i][j]+e);
  // ...
}

对三个主要计算循环应用循环分块，将大数组分割成适合缓存的小块。
// 分块后的ey更新循环
int tile_size = 32; // 根据L1缓存大小调整
for (i = 1; i < _PB_NX; i += tile_size) {
  for (j = 0; j < _PB_NY; j += tile_size) {
    int i_end = min(i + tile_size, _PB_NX);
    int j_end = min(j + tile_size, _PB_NY);
    for (int ii = i; ii < i_end; ii++) {
      for (int jj = j; jj < j_end; jj++) {
        ey[ii][jj] = ey[ii][jj] - SCALAR_VAL(0.5)*(hz[ii][jj]-hz[ii-1][jj]);
      }
    }
  }
}

将数组从AoS布局改为SoA布局，提高内存访问连续性。
// 原布局: DATA_TYPE ex[NX][NY];
// 新布局: DATA_TYPE* ex = malloc(NX*NY*sizeof(DATA_TYPE));
// 访问方式: ex[i*NY + j] 改为 ex[j*NX + i] (转置)
// 或者使用结构数组: struct Field { DATA_TYPE ex, ey, hz; } fields[NX*NY];

将三个主要计算循环融合，减少对同一数组的多次遍历。
// 融合ey和ex更新循环
for (i = 1; i < _PB_NX; i++) {
  for (j = 1; j < _PB_NY; j++) {
    ey[i][j] = ey[i][j] - SCALAR_VAL(0.5)*(hz[i][j]-hz[i-1][j]);
    ex[i][j] = ex[i][j] - SCALAR_VAL(0.5)*(hz[i][j]-hz[i][j-1]);
  }
}
